INSERT INTO question (id, chapter_id, subject_id, type, difficulty, content, options, answer, analysis, year) VALUES
(1,5,1,'SINGLE','EASY','在长度为19的顺序表中插入一个元素，平均需要移动的元素个数是？','[{"key": "A", "value": "n"}, {"key": "B", "value": "n/2"}, {"key": "C", "value": "(n-1)/2"}, {"key": "D", "value": "n-1"}]','B','共有n+1个插入位置，第i个位置需移动n-i+1个元素，平均移动n/2个。',2009),
(2,5,1,'SINGLE','EASY','在长度为19的顺序表中删除第15个元素，需要移动的元素个数是？','[{"key": "A", "value": "i"}, {"key": "B", "value": "n-i"}, {"key": "C", "value": "n-i+1"}, {"key": "D", "value": "n-i-1"}]','B','删除第i个元素后，后面的n-i个元素前移一位。',2009),
(3,5,1,'SINGLE','MEDIUM','在单链表中，在p所指结点之后插入s所指结点，正确的操作是？','[{"key": "A", "value": "p->next=s; s->next=p->next"}, {"key": "B", "value": "s->next=p->next; p->next=s"}, {"key": "C", "value": "p->next=s->next; s->next=p"}, {"key": "D", "value": "s->next=p; p->next=s"}]','B','先将s->next指向p的后继，再将p->next指向s。',2009),
(4,5,1,'SINGLE','MEDIUM','在单链表中删除p结点的后继结点，时间复杂度为？','[{"key": "A", "value": "O(1)"}, {"key": "B", "value": "O(n)"}, {"key": "C", "value": "O(log n)"}, {"key": "D", "value": "O(n^2)"}]','A','已知p，删除后继只需修改p->next指针，O(1)。',2009),
(5,5,1,'SINGLE','MEDIUM','带头结点的循环单链表，在表头插入结点的时间复杂度是？','[{"key": "A", "value": "O(1)"}, {"key": "B", "value": "O(n)"}, {"key": "C", "value": "O(log n)"}, {"key": "D", "value": "O(n^2)"}]','A','通过头指针可直接定位，O(1)完成插入。',2009),
(6,6,1,'SINGLE','EASY','栈的操作特性是？','[{"key": "A", "value": "先进先出"}, {"key": "B", "value": "先进后出"}, {"key": "C", "value": "随机存取"}, {"key": "D", "value": "按值存取"}]','B','栈(LIFO)仅在栈顶进行插入和删除。',2009),
(7,6,1,'SINGLE','MEDIUM','入栈序列为1,2,3,4,5，以下哪个不可能是出栈序列？','[{"key": "A", "value": "5,4,3,2,1"}, {"key": "B", "value": "4,5,3,2,1"}, {"key": "C", "value": "4,3,5,1,2"}, {"key": "D", "value": "1,2,3,4,5"}]','C','4和3出栈后栈内[1,2]，1不可能先于2出栈。',2009),
(8,6,1,'SINGLE','MEDIUM','循环队列用数组A[0..m-1]，front指向队头，rear指向队尾下一位置，元素个数为？','[{"key": "A", "value": "(rear-front+m)%m"}, {"key": "B", "value": "rear-front"}, {"key": "C", "value": "rear-front+1"}, {"key": "D", "value": "(rear-front+1+m)%m"}]','A','循环队列元素个数=(rear-front+m)%m。',2009),
(9,6,1,'SINGLE','MEDIUM','广度优先搜索(BFS)使用什么数据结构？','[{"key": "A", "value": "栈"}, {"key": "B", "value": "队列"}, {"key": "C", "value": "二叉树"}, {"key": "D", "value": "散列表"}]','B','BFS逐层访问，使用队列保存待访问结点。',2009),
(10,7,1,'SINGLE','EASY','具有19个结点的完全二叉树，深度为？(根深度=1)','[{"key": "A", "value": "log_2(n)"}, {"key": "B", "value": "floor(log_2 n)+1"}, {"key": "C", "value": "ceil(log_2(n+1))"}, {"key": "D", "value": "n"}]','B','完全二叉树深度=floor(log2 n)+1。',2009),
(11,7,1,'SINGLE','MEDIUM','一棵二叉树前序为ABDECF，中序为DBEAFC，则后序为？','[{"key": "A", "value": "DEBFCA"}, {"key": "B", "value": "EDBFCA"}, {"key": "C", "value": "DEBFAC"}, {"key": "D", "value": "ABDECF"}]','A','由前序知A为根，中序DBE为左子树，FC为右子树。递归得后序DEBFCA。',2009),
(12,7,1,'SINGLE','MEDIUM','在BST中查找关键字，比较次数不取决于？','[{"key": "A", "value": "关键字的值"}, {"key": "B", "value": "结点个数"}, {"key": "C", "value": "树的高度"}, {"key": "D", "value": "关键字在树中的位置"}]','A','BST查找次数取决于目标结点深度，与关键字值大小无关。',2009),
(13,7,1,'SINGLE','HARD','具有19个结点的平衡二叉树最大深度约为？','[{"key": "A", "value": "log_2 n"}, {"key": "B", "value": "1.44log_2 n"}, {"key": "C", "value": "2log_2 n"}, {"key": "D", "value": "n/2"}]','B','AVL树深度不超过1.44log_2(n+2)-0.328。',2009),
(14,7,1,'SINGLE','MEDIUM','哈夫曼树中，权值越大的叶子结点离根越？','[{"key": "A", "value": "远"}, {"key": "B", "value": "近"}, {"key": "C", "value": "不定"}, {"key": "D", "value": "与其他结点相同"}]','B','哈夫曼编码按权值从小到大合并，权值大者路径短。',2009),
(15,8,1,'SINGLE','MEDIUM','n个顶点e条边的无向图，邻接表边结点总数为？','[{"key": "A", "value": "e"}, {"key": "B", "value": "2e"}, {"key": "C", "value": "n+e"}, {"key": "D", "value": "n+2e"}]','B','每条无向边在邻接表中出现两次。',2009),
(16,8,1,'SINGLE','MEDIUM','对有n个顶点e条边的图进行BFS，邻接表存储的时间复杂度是？','[{"key": "A", "value": "O(n)"}, {"key": "B", "value": "O(e)"}, {"key": "C", "value": "O(n+e)"}, {"key": "D", "value": "O(ne)"}]','C','BFS访问所有顶点和边，O(n+e)。',2009),
(17,8,1,'SINGLE','MEDIUM','Prim算法求MST，邻接矩阵存储的时间复杂度是？','[{"key": "A", "value": "O(n)"}, {"key": "B", "value": "O(n+e)"}, {"key": "C", "value": "O(n^2)"}, {"key": "D", "value": "O(elog e)"}]','C','Prim邻接矩阵实现O(n^2)，适合稠密图。',2009),
(18,8,1,'SINGLE','MEDIUM','Dijkstra算法不能处理以下哪种图？','[{"key": "A", "value": "无向图"}, {"key": "B", "value": "有向图"}, {"key": "C", "value": "含负权边的图"}, {"key": "D", "value": "含环的图"}]','C','Dijkstra要求边权非负。负权边用Bellman-Ford。',2009),
(19,9,1,'SINGLE','EASY','在长度为19的有序表中二分查找，最多比较次数为？','[{"key": "A", "value": "n"}, {"key": "B", "value": "ceil(log_2(n+1))"}, {"key": "C", "value": "n/2"}, {"key": "D", "value": "log_2 n"}]','B','二分查找判定树深度=ceil(log_2(n+1))。',2009),
(20,9,1,'SINGLE','MEDIUM','散列表长为13，H(k)=k%13，线性探测法。已插入{4,15,28,17}，再插入41的探测次数为？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','B','41%13=2已占用，探测3→空闲，共2次(初始+1次探测)。',2009),
(21,9,1,'SINGLE','MEDIUM','5阶B树中，除根外每个结点至少有多少个关键字？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','B','m阶B树非根非终端结点关键字数∈[ceil(m/2)-1,m-1]=[2,4]。',2009),
(22,10,1,'SINGLE','MEDIUM','快速排序在什么情况下效率最低？','[{"key": "A", "value": "随机序列"}, {"key": "B", "value": "基本有序序列"}, {"key": "C", "value": "完全逆序"}, {"key": "D", "value": "B和C"}]','D','序列基本有序或逆序时快排退化为O(n^2)。',2009),
(23,10,1,'SINGLE','MEDIUM','堆排序的空间复杂度为？','[{"key": "A", "value": "O(1)"}, {"key": "B", "value": "O(log n)"}, {"key": "C", "value": "O(n)"}, {"key": "D", "value": "O(n^2)"}]','A','堆排序在原数组上建堆排序，空间O(1)。',2009),
(24,10,1,'SINGLE','MEDIUM','归并排序的时间复杂度在最好、最坏、平均情况下？','[{"key": "A", "value": "都是O(nlog n)"}, {"key": "B", "value": "O(n)~O(n^2)"}, {"key": "C", "value": "O(log n)~O(n)"}, {"key": "D", "value": "O(n)~O(nlog n)"}]','A','归并排序三种情况下均为O(nlog_2 n)，稳定排序。',2009),
(25,10,1,'SINGLE','HARD','对10TB数据排序，应选用哪种算法？','[{"key": "A", "value": "快速排序"}, {"key": "B", "value": "堆排序"}, {"key": "C", "value": "归并排序(外排序)"}, {"key": "D", "value": "基数排序"}]','C','10TB数据无法全部装入内存，须用外排序(多路归并)。',2009),
(26,11,1,'SINGLE','EASY','十进制-37在8位计算机中的补码是？','[{"key": "A", "value": "11011011"}, {"key": "B", "value": "10100101"}, {"key": "C", "value": "11011010"}, {"key": "D", "value": "00100101"}]','A','37=00100101，取反=11011010，加1=11011011。',2009),
(27,11,1,'SINGLE','MEDIUM','IEEE754单精度浮点数阶码占几位？','[{"key": "A", "value": "7"}, {"key": "B", "value": "8"}, {"key": "C", "value": "11"}, {"key": "D", "value": "16"}]','B','单精度：1符号+8阶码+23尾数=32位。',2009),
(28,11,1,'SINGLE','MEDIUM','补码加减运算中判断溢出的方法是？','[{"key": "A", "value": "看最高位进位"}, {"key": "B", "value": "看符号位"}, {"key": "C", "value": "双符号位或最高进位异或"}, {"key": "D", "value": "看结果正负"}]','C','溢出判断：最高符号位进位⊕次高数值位进位=1则溢出。',2009),
(29,11,1,'SINGLE','MEDIUM','并行进位加法器中，进位产生函数Gi和进位传递函数Pi分别是？','[{"key": "A", "value": "Gi=AiBi, Pi=Ai+Bi"}, {"key": "B", "value": "Gi=AiBi, Pi=Ai xor Bi"}, {"key": "C", "value": "Gi=Ai+Bi, Pi=AiBi"}, {"key": "D", "value": "Gi=Ai xor Bi, Pi=AiBi"}]','B','Gi=AiBi（本位产生进位），Pi=Ai xor Bi（传递低位进位）。',2009),
(30,12,1,'SINGLE','MEDIUM','Cache采用直接映射，主存块映射到Cache的组号由什么决定？','[{"key": "A", "value": "随机"}, {"key": "B", "value": "主存块号 mod Cache行数"}, {"key": "C", "value": "LRU算法"}, {"key": "D", "value": "FIFO算法"}]','B','直接映射：Cache行号=主存块号 mod Cache总行数。',2009),
(31,12,1,'SINGLE','MEDIUM','写回法(Write Back)的特点不包括？','[{"key": "A", "value": "写命中时不立即写主存"}, {"key": "B", "value": "块替换时写回主存"}, {"key": "C", "value": "需要脏位(dirty bit)"}, {"key": "D", "value": "每次写都同时写主存"}]','D','D是写直达法的特征。写回法只在替换时写回。',2009),
(32,12,1,'SINGLE','MEDIUM','用16K×1位的芯片组成64K×8位的存储器，需要多少片？','[{"key": "A", "value": "4"}, {"key": "B", "value": "16"}, {"key": "C", "value": "32"}, {"key": "D", "value": "64"}]','C','字扩展64K/16K=4倍，位扩展8/1=8倍，共4x8=32片。',2009),
(33,12,1,'SINGLE','MEDIUM','虚拟存储器主要解决什么问题？','[{"key": "A", "value": "提高速度"}, {"key": "B", "value": "扩大容量"}, {"key": "C", "value": "降低成本"}, {"key": "D", "value": "提高可靠性"}]','B','虚拟存储器在逻辑上扩大主存容量，让程序可超过物理内存大小运行。',2009),
(34,13,1,'SINGLE','EASY','寄存器间接寻址中，操作数在？','[{"key": "A", "value": "指令中"}, {"key": "B", "value": "寄存器中"}, {"key": "C", "value": "内存中"}, {"key": "D", "value": "堆栈中"}]','C','寄存器间接寻址：指令指定寄存器，寄存器内容为地址，操作数在对应内存中。',2009),
(35,13,1,'SINGLE','MEDIUM','某指令系统有19条指令，操作码定长编码，最少需几位？','[{"key": "A", "value": "5"}, {"key": "B", "value": "6"}, {"key": "C", "value": "7"}, {"key": "D", "value": "8"}]','B','64<19? 需ceil(log2 n)位。2^6=64。如指令数>64则需7位，以此类推。',2009),
(36,13,1,'SINGLE','MEDIUM','关于RISC和CISC的描述，正确的是？','[{"key": "A", "value": "RISC指令数量多"}, {"key": "B", "value": "CISC采用硬布线控制"}, {"key": "C", "value": "RISC指令长度固定"}, {"key": "D", "value": "CISC指令执行快"}]','C','RISC精简指令集，指令长度固定，多用硬布线。处理器运行快，单条指令未必。',2009),
(37,14,1,'SINGLE','EASY','程序计数器PC存放的是？','[{"key": "A", "value": "当前指令"}, {"key": "B", "value": "下一条指令地址"}, {"key": "C", "value": "操作数"}, {"key": "D", "value": "运算结果"}]','B','PC存放下一条要执行指令的地址。',2009),
(38,14,1,'SINGLE','MEDIUM','5级流水线，每级2ns，执行100条指令需要？','[{"key": "A", "value": "200ns"}, {"key": "B", "value": "208ns"}, {"key": "C", "value": "500ns"}, {"key": "D", "value": "1000ns"}]','B','流水线时间=(k+n-1)*Δt=(5+100-1)*2=208ns。',2009),
(39,14,1,'SINGLE','MEDIUM','以下冒险类型中，哪种不能通过旁路技术解决？','[{"key": "A", "value": "RAW数据冒险"}, {"key": "B", "value": "WAR数据冒险"}, {"key": "C", "value": "WAW数据冒险"}, {"key": "D", "value": "控制冒险"}]','D','控制冒险由分支引起，需分支预测或流水线暂停。',2009),
(40,15,1,'SINGLE','MEDIUM','系统总线按传输内容分为？','[{"key": "A", "value": "地址总线、数据总线、控制总线"}, {"key": "B", "value": "内部总线、外部总线"}, {"key": "C", "value": "串行总线、并行总线"}, {"key": "D", "value": "单向总线、双向总线"}]','A','系统总线包括地址总线、数据总线、控制总线三类。',2009),
(41,15,1,'SINGLE','MEDIUM','CPU响应中断后，首先完成的操作是？','[{"key": "A", "value": "执行中断服务程序"}, {"key": "B", "value": "关中断，保护断点"}, {"key": "C", "value": "恢复现场"}, {"key": "D", "value": "开中断"}]','B','中断响应：关中断→保护断点和程序状态→取中断向量。',2009),
(42,15,1,'SINGLE','MEDIUM','DMA方式与程序中断方式的主要区别是？','[{"key": "A", "value": "DMA更快"}, {"key": "B", "value": "DMA不需要CPU干预数据传输"}, {"key": "C", "value": "中断不需要DMA控制器"}, {"key": "D", "value": "没有区别"}]','B','DMA方式下数据传送由DMA控制器完成，CPU仅参与开始和结束处理。',2009),
(43,16,1,'SINGLE','EASY','进程从运行态变为阻塞态的原因是？','[{"key": "A", "value": "时间片用完"}, {"key": "B", "value": "等待某事件发生"}, {"key": "C", "value": "被高优先级进程抢占"}, {"key": "D", "value": "进程创建"}]','B','运行→阻塞：进程主动等待某事件(如I/O完成)。',2009),
(44,16,1,'SINGLE','MEDIUM','同一进程中的多个线程，不共享的是？','[{"key": "A", "value": "地址空间"}, {"key": "B", "value": "打开的文件"}, {"key": "C", "value": "栈和寄存器"}, {"key": "D", "value": "全局变量"}]','C','线程独享：栈、寄存器、程序计数器。共享：地址空间、文件、全局变量。',2009),
(45,16,1,'SINGLE','MEDIUM','n个进程互斥访问临界资源，信号量取值范围是？','[{"key": "A", "value": "0到1"}, {"key": "B", "value": "-(n-1)到1"}, {"key": "C", "value": "1到n"}, {"key": "D", "value": "0到n"}]','B','互斥信号量初值1，每P减1。范围[-(n-1),1]。',2009),
(46,16,1,'SINGLE','HARD','死锁预防中，破坏"请求与保持"条件的方法是？','[{"key": "A", "value": "一次性分配所有资源"}, {"key": "B", "value": "允许抢占"}, {"key": "C", "value": "资源有序分配"}, {"key": "D", "value": "银行家算法"}]','A','一次性分配所有资源：进程运行前获得全部所需资源，运行中不再请求。',2009),
(47,16,1,'SINGLE','MEDIUM','时间片轮转调度中，时间片过小会导致？','[{"key": "A", "value": "响应变快"}, {"key": "B", "value": "频繁切换，开销增大"}, {"key": "C", "value": "退化为FCFS"}, {"key": "D", "value": "死锁"}]','B','时间片过小→频繁上下文切换→CPU有效利用率降低。',2009),
(48,6,1,'SINGLE','MEDIUM','循环队列用数组A[0..m-1]，front指向队头，rear指向队尾下一位置，元素个数为？','[{"key": "A", "value": "(rear-front+m)%m"}, {"key": "B", "value": "rear-front"}, {"key": "C", "value": "rear-front+1"}, {"key": "D", "value": "(rear-front+1+m)%m"}]','A','循环队列元素个数=(rear-front+m)%m。',2010),
(49,6,1,'SINGLE','MEDIUM','广度优先搜索(BFS)使用什么数据结构？','[{"key": "A", "value": "栈"}, {"key": "B", "value": "队列"}, {"key": "C", "value": "二叉树"}, {"key": "D", "value": "散列表"}]','B','BFS逐层访问，使用队列保存待访问结点。',2010),
(50,7,1,'SINGLE','EASY','具有5个结点的完全二叉树，深度为？(根深度=1)','[{"key": "A", "value": "log_2(n)"}, {"key": "B", "value": "floor(log_2 n)+1"}, {"key": "C", "value": "ceil(log_2(n+1))"}, {"key": "D", "value": "n"}]','B','完全二叉树深度=floor(log2 n)+1。',2010);
