(438,6,1,'SINGLE','MEDIUM','入栈序列为1,2,3,4,5，以下哪个不可能是出栈序列？','[{"key": "A", "value": "5,4,3,2,1"}, {"key": "B", "value": "4,5,3,2,1"}, {"key": "C", "value": "4,3,5,1,2"}, {"key": "D", "value": "1,2,3,4,5"}]','C','4和3出栈后栈内[1,2]，1不可能先于2出栈。',2018),
(439,6,1,'SINGLE','MEDIUM','循环队列用数组A[0..m-1]，front指向队头，rear指向队尾下一位置，元素个数为？','[{"key": "A", "value": "(rear-front+m)%m"}, {"key": "B", "value": "rear-front"}, {"key": "C", "value": "rear-front+1"}, {"key": "D", "value": "(rear-front+1+m)%m"}]','A','循环队列元素个数=(rear-front+m)%m。',2018),
