(492,9,1,'SINGLE','MEDIUM','5阶B树中，除根外每个结点至少有多少个关键字？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','B','m阶B树非根非终端结点关键字数∈[ceil(m/2)-1,m-1]=[2,4]。',2019),
(493,10,1,'SINGLE','MEDIUM','快速排序在什么情况下效率最低？','[{"key": "A", "value": "随机序列"}, {"key": "B", "value": "基本有序序列"}, {"key": "C", "value": "完全逆序"}, {"key": "D", "value": "B和C"}]','D','序列基本有序或逆序时快排退化为O(n^2)。',2019),
(494,10,1,'SINGLE','MEDIUM','堆排序的空间复杂度为？','[{"key": "A", "value": "O(1)"}, {"key": "B", "value": "O(log n)"}, {"key": "C", "value": "O(n)"}, {"key": "D", "value": "O(n^2)"}]','A','堆排序在原数组上建堆排序，空间O(1)。',2019),
(495,10,1,'SINGLE','MEDIUM','归并排序的时间复杂度在最好、最坏、平均情况下？','[{"key": "A", "value": "都是O(nlog n)"}, {"key": "B", "value": "O(n)~O(n^2)"}, {"key": "C", "value": "O(log n)~O(n)"}, {"key": "D", "value": "O(n)~O(nlog n)"}]','A','归并排序三种情况下均为O(nlog_2 n)，稳定排序。',2019),
(496,10,1,'SINGLE','MEDIUM','对10TB数据排序，应选用哪种算法？','[{"key": "A", "value": "快速排序"}, {"key": "B", "value": "堆排序"}, {"key": "C", "value": "归并排序(外排序)"}, {"key": "D", "value": "基数排序"}]','C','10TB数据无法全部装入内存，须用外排序(多路归并)。',2019),
(497,11,1,'SINGLE','EASY','十进制-37在8位计算机中的补码是？','[{"key": "A", "value": "11011011"}, {"key": "B", "value": "10100101"}, {"key": "C", "value": "11011010"}, {"key": "D", "value": "00100101"}]','A','37=00100101，取反=11011010，加1=11011011。',2019),
(498,11,1,'SINGLE','MEDIUM','IEEE754单精度浮点数阶码占几位？','[{"key": "A", "value": "7"}, {"key": "B", "value": "8"}, {"key": "C", "value": "11"}, {"key": "D", "value": "16"}]','B','单精度：1符号+8阶码+23尾数=32位。',2019),
(499,11,1,'SINGLE','MEDIUM','补码加减运算中判断溢出的方法是？','[{"key": "A", "value": "看最高位进位"}, {"key": "B", "value": "看符号位"}, {"key": "C", "value": "双符号位或最高进位异或"}, {"key": "D", "value": "看结果正负"}]','C','溢出判断：最高符号位进位⊕次高数值位进位=1则溢出。',2019),
(500,11,1,'SINGLE','MEDIUM','并行进位加法器中，进位产生函数Gi和进位传递函数Pi分别是？','[{"key": "A", "value": "Gi=AiBi, Pi=Ai+Bi"}, {"key": "B", "value": "Gi=AiBi, Pi=Ai xor Bi"}, {"key": "C", "value": "Gi=Ai+Bi, Pi=AiBi"}, {"key": "D", "value": "Gi=Ai xor Bi, Pi=AiBi"}]','B','Gi=AiBi（本位产生进位），Pi=Ai xor Bi（传递低位进位）。',2019);
INSERT INTO question (id, chapter_id, subject_id, type, difficulty, content, options, answer, analysis, year) VALUES
(501,12,1,'SINGLE','MEDIUM','Cache采用直接映射，主存块映射到Cache的组号由什么决定？','[{"key": "A", "value": "随机"}, {"key": "B", "value": "主存块号 mod Cache行数"}, {"key": "C", "value": "LRU算法"}, {"key": "D", "value": "FIFO算法"}]','B','直接映射：Cache行号=主存块号 mod Cache总行数。',2019),
(502,12,1,'SINGLE','MEDIUM','写回法(Write Back)的特点不包括？','[{"key": "A", "value": "写命中时不立即写主存"}, {"key": "B", "value": "块替换时写回主存"}, {"key": "C", "value": "需要脏位(dirty bit)"}, {"key": "D", "value": "每次写都同时写主存"}]','D','D是写直达法的特征。写回法只在替换时写回。',2019),
(503,12,1,'SINGLE','MEDIUM','用16K×1位的芯片组成64K×8位的存储器，需要多少片？','[{"key": "A", "value": "4"}, {"key": "B", "value": "16"}, {"key": "C", "value": "32"}, {"key": "D", "value": "64"}]','C','字扩展64K/16K=4倍，位扩展8/1=8倍，共4x8=32片。',2019),
(504,12,1,'SINGLE','MEDIUM','虚拟存储器主要解决什么问题？','[{"key": "A", "value": "提高速度"}, {"key": "B", "value": "扩大容量"}, {"key": "C", "value": "降低成本"}, {"key": "D", "value": "提高可靠性"}]','B','虚拟存储器在逻辑上扩大主存容量，让程序可超过物理内存大小运行。',2019),
(505,13,1,'SINGLE','EASY','寄存器间接寻址中，操作数在？','[{"key": "A", "value": "指令中"}, {"key": "B", "value": "寄存器中"}, {"key": "C", "value": "内存中"}, {"key": "D", "value": "堆栈中"}]','C','寄存器间接寻址：指令指定寄存器，寄存器内容为地址，操作数在对应内存中。',2019),
(506,13,1,'SINGLE','MEDIUM','某指令系统有14条指令，操作码定长编码，最少需几位？','[{"key": "A", "value": "5"}, {"key": "B", "value": "6"}, {"key": "C", "value": "7"}, {"key": "D", "value": "8"}]','B','64<14? 需ceil(log2 n)位。2^6=64。如指令数>64则需7位，以此类推。',2019),
(507,13,1,'SINGLE','MEDIUM','关于RISC和CISC的描述，正确的是？','[{"key": "A", "value": "RISC指令数量多"}, {"key": "B", "value": "CISC采用硬布线控制"}, {"key": "C", "value": "RISC指令长度固定"}, {"key": "D", "value": "CISC指令执行快"}]','C','RISC精简指令集，指令长度固定，多用硬布线。处理器运行快，单条指令未必。',2019),
(508,14,1,'SINGLE','EASY','程序计数器PC存放的是？','[{"key": "A", "value": "当前指令"}, {"key": "B", "value": "下一条指令地址"}, {"key": "C", "value": "操作数"}, {"key": "D", "value": "运算结果"}]','B','PC存放下一条要执行指令的地址。',2019),
(509,14,1,'SINGLE','MEDIUM','5级流水线，每级2ns，执行100条指令需要？','[{"key": "A", "value": "200ns"}, {"key": "B", "value": "208ns"}, {"key": "C", "value": "500ns"}, {"key": "D", "value": "1000ns"}]','B','流水线时间=(k+n-1)*Δt=(5+100-1)*2=208ns。',2019),
(510,14,1,'SINGLE','MEDIUM','以下冒险类型中，哪种不能通过旁路技术解决？','[{"key": "A", "value": "RAW数据冒险"}, {"key": "B", "value": "WAR数据冒险"}, {"key": "C", "value": "WAW数据冒险"}, {"key": "D", "value": "控制冒险"}]','D','控制冒险由分支引起，需分支预测或流水线暂停。',2019),
(511,15,1,'SINGLE','MEDIUM','系统总线按传输内容分为？','[{"key": "A", "value": "地址总线、数据总线、控制总线"}, {"key": "B", "value": "内部总线、外部总线"}, {"key": "C", "value": "串行总线、并行总线"}, {"key": "D", "value": "单向总线、双向总线"}]','A','系统总线包括地址总线、数据总线、控制总线三类。',2019),
(512,15,1,'SINGLE','MEDIUM','CPU响应中断后，首先完成的操作是？','[{"key": "A", "value": "执行中断服务程序"}, {"key": "B", "value": "关中断，保护断点"}, {"key": "C", "value": "恢复现场"}, {"key": "D", "value": "开中断"}]','B','中断响应：关中断→保护断点和程序状态→取中断向量。',2019),
(513,15,1,'SINGLE','MEDIUM','DMA方式与程序中断方式的主要区别是？','[{"key": "A", "value": "DMA更快"}, {"key": "B", "value": "DMA不需要CPU干预数据传输"}, {"key": "C", "value": "中断不需要DMA控制器"}, {"key": "D", "value": "没有区别"}]','B','DMA方式下数据传送由DMA控制器完成，CPU仅参与开始和结束处理。',2019),
(514,16,1,'SINGLE','EASY','进程从运行态变为阻塞态的原因是？','[{"key": "A", "value": "时间片用完"}, {"key": "B", "value": "等待某事件发生"}, {"key": "C", "value": "被高优先级进程抢占"}, {"key": "D", "value": "进程创建"}]','B','运行→阻塞：进程主动等待某事件(如I/O完成)。',2019),
(515,16,1,'SINGLE','MEDIUM','同一进程中的多个线程，不共享的是？','[{"key": "A", "value": "地址空间"}, {"key": "B", "value": "打开的文件"}, {"key": "C", "value": "栈和寄存器"}, {"key": "D", "value": "全局变量"}]','C','线程独享：栈、寄存器、程序计数器。共享：地址空间、文件、全局变量。',2019),
(516,16,1,'SINGLE','MEDIUM','n个进程互斥访问临界资源，信号量取值范围是？','[{"key": "A", "value": "0到1"}, {"key": "B", "value": "-(n-1)到1"}, {"key": "C", "value": "1到n"}, {"key": "D", "value": "0到n"}]','B','互斥信号量初值1，每P减1。范围[-(n-1),1]。',2019),
(517,16,1,'SINGLE','MEDIUM','死锁预防中，破坏"请求与保持"条件的方法是？','[{"key": "A", "value": "一次性分配所有资源"}, {"key": "B", "value": "允许抢占"}, {"key": "C", "value": "资源有序分配"}, {"key": "D", "value": "银行家算法"}]','A','一次性分配所有资源：进程运行前获得全部所需资源，运行中不再请求。',2019),
(518,6,1,'SINGLE','MEDIUM','入栈序列为1,2,3,4,5，以下哪个不可能是出栈序列？','[{"key": "A", "value": "5,4,3,2,1"}, {"key": "B", "value": "4,5,3,2,1"}, {"key": "C", "value": "4,3,5,1,2"}, {"key": "D", "value": "1,2,3,4,5"}]','C','4和3出栈后栈内[1,2]，1不可能先于2出栈。',2020),
(519,6,1,'SINGLE','MEDIUM','循环队列用数组A[0..m-1]，front指向队头，rear指向队尾下一位置，元素个数为？','[{"key": "A", "value": "(rear-front+m)%m"}, {"key": "B", "value": "rear-front"}, {"key": "C", "value": "rear-front+1"}, {"key": "D", "value": "(rear-front+1+m)%m"}]','A','循环队列元素个数=(rear-front+m)%m。',2020),
(520,6,1,'SINGLE','MEDIUM','广度优先搜索(BFS)使用什么数据结构？','[{"key": "A", "value": "栈"}, {"key": "B", "value": "队列"}, {"key": "C", "value": "二叉树"}, {"key": "D", "value": "散列表"}]','B','BFS逐层访问，使用队列保存待访问结点。',2020),
(521,7,1,'SINGLE','EASY','具有15个结点的完全二叉树，深度为？(根深度=1)','[{"key": "A", "value": "log_2(n)"}, {"key": "B", "value": "floor(log_2 n)+1"}, {"key": "C", "value": "ceil(log_2(n+1))"}, {"key": "D", "value": "n"}]','B','完全二叉树深度=floor(log2 n)+1。',2020),
