(597,16,1,'SINGLE','HARD','死锁预防中，破坏"请求与保持"条件的方法是？','[{"key": "A", "value": "一次性分配所有资源"}, {"key": "B", "value": "允许抢占"}, {"key": "C", "value": "资源有序分配"}, {"key": "D", "value": "银行家算法"}]','A','一次性分配所有资源：进程运行前获得全部所需资源，运行中不再请求。',2021),
(598,16,1,'SINGLE','MEDIUM','时间片轮转调度中，时间片过小会导致？','[{"key": "A", "value": "响应变快"}, {"key": "B", "value": "频繁切换，开销增大"}, {"key": "C", "value": "退化为FCFS"}, {"key": "D", "value": "死锁"}]','B','时间片过小→频繁上下文切换→CPU有效利用率降低。',2021),
(599,17,1,'SINGLE','MEDIUM','页面大小4KB，逻辑地址2FA6H，页号2对应块号6，物理地址为？','[{"key": "A", "value": "6FA6H"}, {"key": "B", "value": "2FA6H"}, {"key": "C", "value": "1FA6H"}, {"key": "D", "value": "8FA6H"}]','A','页内偏移=FA6H。物理地址=6x4096+FA6H=18000H+FA6H=6FA6H。',2021),
(600,17,1,'SINGLE','MEDIUM','可能出现Belady异常的页面置换算法是？','[{"key": "A", "value": "OPT"}, {"key": "B", "value": "LRU"}, {"key": "C", "value": "FIFO"}, {"key": "D", "value": "CLOCK"}]','C','FIFO可能出现Belady异常：分配块增多，缺页率反而增加。',2021);
INSERT INTO question (id, chapter_id, subject_id, type, difficulty, content, options, answer, analysis, year) VALUES
(601,17,1,'SINGLE','MEDIUM','分段存储管理的主要优点是？','[{"key": "A", "value": "无外部碎片"}, {"key": "B", "value": "便于共享和保护"}, {"key": "C", "value": "内存利用率高"}, {"key": "D", "value": "地址转换快"}]','B','分段按逻辑单位划分，便于共享、保护和动态链接。',2021),
(602,18,1,'SINGLE','EASY','Unix文件系统中，索引结点(inode)不包含？','[{"key": "A", "value": "文件大小"}, {"key": "B", "value": "文件所有者"}, {"key": "C", "value": "文件名"}, {"key": "D", "value": "访问权限"}]','C','文件名存放在目录项中，不在inode中。',2021),
(603,18,1,'SINGLE','MEDIUM','采用索引分配方式的文件系统，优点是？','[{"key": "A", "value": "支持随机访问"}, {"key": "B", "value": "无外部碎片"}, {"key": "C", "value": "实现简单"}, {"key": "D", "value": "不需要索引表"}]','A','索引分配通过索引块记录所有数据块地址，支持直接访问任意块。',2021),
(604,19,1,'SINGLE','MEDIUM','以下磁盘调度算法，哪个可能导致饥饿？','[{"key": "A", "value": "FCFS"}, {"key": "B", "value": "SSTF"}, {"key": "C", "value": "SCAN"}, {"key": "D", "value": "C-SCAN"}]','B','SSTF(最短寻道优先)：远离磁头的请求可能长期得不到服务。',2021),
(605,19,1,'SINGLE','EASY','SPOOLing技术实现了？','[{"key": "A", "value": "将独占设备改造为共享设备"}, {"key": "B", "value": "提高CPU速度"}, {"key": "C", "value": "扩展内存"}, {"key": "D", "value": "加速磁盘"}]','A','假脱机将独占设备虚拟化为共享设备。',2021),
(606,20,1,'SINGLE','EASY','OSI参考模型有几层？','[{"key": "A", "value": "4"}, {"key": "B", "value": "5"}, {"key": "C", "value": "7"}, {"key": "D", "value": "9"}]','C','OSI七层：物理层、链路层、网络层、传输层、会话层、表示层、应用层。',2021),
(607,20,1,'SINGLE','EASY','TCP/IP模型中，网络接口层对应OSI哪两层？','[{"key": "A", "value": "物理层和数据链路层"}, {"key": "B", "value": "链路层和网络层"}, {"key": "C", "value": "网络层和传输层"}, {"key": "D", "value": "物理层和网络层"}]','A','TCP/IP网络接口层对应OSI物理层+数据链路层。',2021),
(608,21,1,'SINGLE','MEDIUM','曼彻斯特编码的编码效率为？','[{"key": "A", "value": "25%"}, {"key": "B", "value": "50%"}, {"key": "C", "value": "75%"}, {"key": "D", "value": "100%"}]','B','曼彻斯特编码每位有两个码元，效率50%。',2021),
(609,22,1,'SINGLE','MEDIUM','CSMA/CD协议中争用期长度为？','[{"key": "A", "value": "端到端传播时延"}, {"key": "B", "value": "两倍端到端传播时延"}, {"key": "C", "value": "数据帧发送时延"}, {"key": "D", "value": "随机时间"}]','B','争用期=2tau(两倍单程传播时延，即往返时延RTT)。',2021),
(610,22,1,'SINGLE','MEDIUM','以太网最小帧长64字节，目的是？','[{"key": "A", "value": "提高效率"}, {"key": "B", "value": "确保冲突检测"}, {"key": "C", "value": "对齐数据"}, {"key": "D", "value": "减少开销"}]','B','最小帧长确保发送完之前能检测到冲突。',2021),
(611,22,1,'SINGLE','MEDIUM','生成多项式G(x)=x^3+x+1，CRC校验码长度为？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','C','CRC校验码位数=生成多项式最高次幂=3。',2021),
(612,9,1,'SINGLE','MEDIUM','5阶B树中，除根外每个结点至少有多少个关键字？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','B','m阶B树非根非终端结点关键字数∈[ceil(m/2)-1,m-1]=[2,4]。',2022),
(613,10,1,'SINGLE','MEDIUM','快速排序在什么情况下效率最低？','[{"key": "A", "value": "随机序列"}, {"key": "B", "value": "基本有序序列"}, {"key": "C", "value": "完全逆序"}, {"key": "D", "value": "B和C"}]','D','序列基本有序或逆序时快排退化为O(n^2)。',2022),
(614,10,1,'SINGLE','MEDIUM','堆排序的空间复杂度为？','[{"key": "A", "value": "O(1)"}, {"key": "B", "value": "O(log n)"}, {"key": "C", "value": "O(n)"}, {"key": "D", "value": "O(n^2)"}]','A','堆排序在原数组上建堆排序，空间O(1)。',2022),
(615,10,1,'SINGLE','MEDIUM','归并排序的时间复杂度在最好、最坏、平均情况下？','[{"key": "A", "value": "都是O(nlog n)"}, {"key": "B", "value": "O(n)~O(n^2)"}, {"key": "C", "value": "O(log n)~O(n)"}, {"key": "D", "value": "O(n)~O(nlog n)"}]','A','归并排序三种情况下均为O(nlog_2 n)，稳定排序。',2022),
(616,10,1,'SINGLE','MEDIUM','对10TB数据排序，应选用哪种算法？','[{"key": "A", "value": "快速排序"}, {"key": "B", "value": "堆排序"}, {"key": "C", "value": "归并排序(外排序)"}, {"key": "D", "value": "基数排序"}]','C','10TB数据无法全部装入内存，须用外排序(多路归并)。',2022),
(617,11,1,'SINGLE','EASY','十进制-37在8位计算机中的补码是？','[{"key": "A", "value": "11011011"}, {"key": "B", "value": "10100101"}, {"key": "C", "value": "11011010"}, {"key": "D", "value": "00100101"}]','A','37=00100101，取反=11011010，加1=11011011。',2022),
(618,11,1,'SINGLE','MEDIUM','IEEE754单精度浮点数阶码占几位？','[{"key": "A", "value": "7"}, {"key": "B", "value": "8"}, {"key": "C", "value": "11"}, {"key": "D", "value": "16"}]','B','单精度：1符号+8阶码+23尾数=32位。',2022),
(619,11,1,'SINGLE','MEDIUM','补码加减运算中判断溢出的方法是？','[{"key": "A", "value": "看最高位进位"}, {"key": "B", "value": "看符号位"}, {"key": "C", "value": "双符号位或最高进位异或"}, {"key": "D", "value": "看结果正负"}]','C','溢出判断：最高符号位进位⊕次高数值位进位=1则溢出。',2022),
(620,11,1,'SINGLE','MEDIUM','并行进位加法器中，进位产生函数Gi和进位传递函数Pi分别是？','[{"key": "A", "value": "Gi=AiBi, Pi=Ai+Bi"}, {"key": "B", "value": "Gi=AiBi, Pi=Ai xor Bi"}, {"key": "C", "value": "Gi=Ai+Bi, Pi=AiBi"}, {"key": "D", "value": "Gi=Ai xor Bi, Pi=AiBi"}]','B','Gi=AiBi（本位产生进位），Pi=Ai xor Bi（传递低位进位）。',2022),
(621,12,1,'SINGLE','MEDIUM','Cache采用直接映射，主存块映射到Cache的组号由什么决定？','[{"key": "A", "value": "随机"}, {"key": "B", "value": "主存块号 mod Cache行数"}, {"key": "C", "value": "LRU算法"}, {"key": "D", "value": "FIFO算法"}]','B','直接映射：Cache行号=主存块号 mod Cache总行数。',2022),
(622,12,1,'SINGLE','MEDIUM','写回法(Write Back)的特点不包括？','[{"key": "A", "value": "写命中时不立即写主存"}, {"key": "B", "value": "块替换时写回主存"}, {"key": "C", "value": "需要脏位(dirty bit)"}, {"key": "D", "value": "每次写都同时写主存"}]','D','D是写直达法的特征。写回法只在替换时写回。',2022),
(623,12,1,'SINGLE','MEDIUM','用16K×1位的芯片组成64K×8位的存储器，需要多少片？','[{"key": "A", "value": "4"}, {"key": "B", "value": "16"}, {"key": "C", "value": "32"}, {"key": "D", "value": "64"}]','C','字扩展64K/16K=4倍，位扩展8/1=8倍，共4x8=32片。',2022),
(624,12,1,'SINGLE','MEDIUM','虚拟存储器主要解决什么问题？','[{"key": "A", "value": "提高速度"}, {"key": "B", "value": "扩大容量"}, {"key": "C", "value": "降低成本"}, {"key": "D", "value": "提高可靠性"}]','B','虚拟存储器在逻辑上扩大主存容量，让程序可超过物理内存大小运行。',2022),
(625,13,1,'SINGLE','EASY','寄存器间接寻址中，操作数在？','[{"key": "A", "value": "指令中"}, {"key": "B", "value": "寄存器中"}, {"key": "C", "value": "内存中"}, {"key": "D", "value": "堆栈中"}]','C','寄存器间接寻址：指令指定寄存器，寄存器内容为地址，操作数在对应内存中。',2022),
(626,13,1,'SINGLE','MEDIUM','某指令系统有17条指令，操作码定长编码，最少需几位？','[{"key": "A", "value": "5"}, {"key": "B", "value": "6"}, {"key": "C", "value": "7"}, {"key": "D", "value": "8"}]','B','64<17? 需ceil(log2 n)位。2^6=64。如指令数>64则需7位，以此类推。',2022),
(627,13,1,'SINGLE','MEDIUM','关于RISC和CISC的描述，正确的是？','[{"key": "A", "value": "RISC指令数量多"}, {"key": "B", "value": "CISC采用硬布线控制"}, {"key": "C", "value": "RISC指令长度固定"}, {"key": "D", "value": "CISC指令执行快"}]','C','RISC精简指令集，指令长度固定，多用硬布线。处理器运行快，单条指令未必。',2022),
(628,14,1,'SINGLE','EASY','程序计数器PC存放的是？','[{"key": "A", "value": "当前指令"}, {"key": "B", "value": "下一条指令地址"}, {"key": "C", "value": "操作数"}, {"key": "D", "value": "运算结果"}]','B','PC存放下一条要执行指令的地址。',2022),
(629,14,1,'SINGLE','MEDIUM','5级流水线，每级2ns，执行100条指令需要？','[{"key": "A", "value": "200ns"}, {"key": "B", "value": "208ns"}, {"key": "C", "value": "500ns"}, {"key": "D", "value": "1000ns"}]','B','流水线时间=(k+n-1)*Δt=(5+100-1)*2=208ns。',2022),
(630,14,1,'SINGLE','MEDIUM','以下冒险类型中，哪种不能通过旁路技术解决？','[{"key": "A", "value": "RAW数据冒险"}, {"key": "B", "value": "WAR数据冒险"}, {"key": "C", "value": "WAW数据冒险"}, {"key": "D", "value": "控制冒险"}]','D','控制冒险由分支引起，需分支预测或流水线暂停。',2022),
(631,15,1,'SINGLE','MEDIUM','系统总线按传输内容分为？','[{"key": "A", "value": "地址总线、数据总线、控制总线"}, {"key": "B", "value": "内部总线、外部总线"}, {"key": "C", "value": "串行总线、并行总线"}, {"key": "D", "value": "单向总线、双向总线"}]','A','系统总线包括地址总线、数据总线、控制总线三类。',2022),
(632,15,1,'SINGLE','MEDIUM','CPU响应中断后，首先完成的操作是？','[{"key": "A", "value": "执行中断服务程序"}, {"key": "B", "value": "关中断，保护断点"}, {"key": "C", "value": "恢复现场"}, {"key": "D", "value": "开中断"}]','B','中断响应：关中断→保护断点和程序状态→取中断向量。',2022),
(633,15,1,'SINGLE','MEDIUM','DMA方式与程序中断方式的主要区别是？','[{"key": "A", "value": "DMA更快"}, {"key": "B", "value": "DMA不需要CPU干预数据传输"}, {"key": "C", "value": "中断不需要DMA控制器"}, {"key": "D", "value": "没有区别"}]','B','DMA方式下数据传送由DMA控制器完成，CPU仅参与开始和结束处理。',2022),
(634,16,1,'SINGLE','EASY','进程从运行态变为阻塞态的原因是？','[{"key": "A", "value": "时间片用完"}, {"key": "B", "value": "等待某事件发生"}, {"key": "C", "value": "被高优先级进程抢占"}, {"key": "D", "value": "进程创建"}]','B','运行→阻塞：进程主动等待某事件(如I/O完成)。',2022),
