(649,22,1,'SINGLE','MEDIUM','CSMA/CD协议中争用期长度为？','[{"key": "A", "value": "端到端传播时延"}, {"key": "B", "value": "两倍端到端传播时延"}, {"key": "C", "value": "数据帧发送时延"}, {"key": "D", "value": "随机时间"}]','B','争用期=2tau(两倍单程传播时延，即往返时延RTT)。',2022),
(650,22,1,'SINGLE','MEDIUM','以太网最小帧长64字节，目的是？','[{"key": "A", "value": "提高效率"}, {"key": "B", "value": "确保冲突检测"}, {"key": "C", "value": "对齐数据"}, {"key": "D", "value": "减少开销"}]','B','最小帧长确保发送完之前能检测到冲突。',2022);
INSERT INTO question (id, chapter_id, subject_id, type, difficulty, content, options, answer, analysis, year) VALUES
(651,22,1,'SINGLE','MEDIUM','生成多项式G(x)=x^3+x+1，CRC校验码长度为？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','C','CRC校验码位数=生成多项式最高次幂=3。',2022),
(652,23,1,'SINGLE','EASY','IP地址192.168.1.0/24的可用主机数是？','[{"key": "A", "value": "254"}, {"key": "B", "value": "255"}, {"key": "C", "value": "256"}, {"key": "D", "value": "253"}]','A','/24=主机号8位，可用=2^8-2=254。',2022),
(653,23,1,'SINGLE','MEDIUM','192.168.1.0/26划分后，每个子网可用地址数？','[{"key": "A", "value": "62"}, {"key": "B", "value": "64"}, {"key": "C", "value": "30"}, {"key": "D", "value": "32"}]','A','/26=主机号6位，可用=2^6-2=62。',2022),
(654,23,1,'SINGLE','MEDIUM','以下使用链路状态算法的路由协议是？','[{"key": "A", "value": "RIP"}, {"key": "B", "value": "OSPF"}, {"key": "C", "value": "BGP"}, {"key": "D", "value": "IGRP"}]','B','OSPF基于Dijkstra算法，使用链路状态数据库。',2022),
(655,23,1,'SINGLE','MEDIUM','NAT的主要作用是？','[{"key": "A", "value": "加密"}, {"key": "B", "value": "地址转换"}, {"key": "C", "value": "过滤"}, {"key": "D", "value": "加速"}]','B','NAT实现私有IP与公网IP转换，缓解IPv4枯竭。',2022),
(656,24,1,'SINGLE','EASY','TCP建立连接需要几次握手？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','C','TCP三次握手：SYN->SYN+ACK->ACK。',2022),
(657,24,1,'SINGLE','MEDIUM','收到3个重复ACK触发什么？','[{"key": "A", "value": "慢开始"}, {"key": "B", "value": "快重传"}, {"key": "C", "value": "拥塞避免"}, {"key": "D", "value": "连接重置"}]','B','3个重复ACK触发快重传，不等超时就重传。',2022),
(658,24,1,'SINGLE','MEDIUM','以下适合用UDP的应用是？','[{"key": "A", "value": "文件传输"}, {"key": "B", "value": "邮件"}, {"key": "C", "value": "视频直播"}, {"key": "D", "value": "网页"}]','C','视频直播实时性要求高，可容忍少量丢包，适合UDP。',2022),
(659,11,1,'SINGLE','MEDIUM','补码加减运算中判断溢出的方法是？','[{"key": "A", "value": "看最高位进位"}, {"key": "B", "value": "看符号位"}, {"key": "C", "value": "双符号位或最高进位异或"}, {"key": "D", "value": "看结果正负"}]','C','溢出判断：最高符号位进位⊕次高数值位进位=1则溢出。',2023),
(660,11,1,'SINGLE','MEDIUM','并行进位加法器中，进位产生函数Gi和进位传递函数Pi分别是？','[{"key": "A", "value": "Gi=AiBi, Pi=Ai+Bi"}, {"key": "B", "value": "Gi=AiBi, Pi=Ai xor Bi"}, {"key": "C", "value": "Gi=Ai+Bi, Pi=AiBi"}, {"key": "D", "value": "Gi=Ai xor Bi, Pi=AiBi"}]','B','Gi=AiBi（本位产生进位），Pi=Ai xor Bi（传递低位进位）。',2023),
(661,12,1,'SINGLE','MEDIUM','Cache采用直接映射，主存块映射到Cache的组号由什么决定？','[{"key": "A", "value": "随机"}, {"key": "B", "value": "主存块号 mod Cache行数"}, {"key": "C", "value": "LRU算法"}, {"key": "D", "value": "FIFO算法"}]','B','直接映射：Cache行号=主存块号 mod Cache总行数。',2023),
(662,12,1,'SINGLE','MEDIUM','写回法(Write Back)的特点不包括？','[{"key": "A", "value": "写命中时不立即写主存"}, {"key": "B", "value": "块替换时写回主存"}, {"key": "C", "value": "需要脏位(dirty bit)"}, {"key": "D", "value": "每次写都同时写主存"}]','D','D是写直达法的特征。写回法只在替换时写回。',2023),
(663,12,1,'SINGLE','MEDIUM','用16K×1位的芯片组成64K×8位的存储器，需要多少片？','[{"key": "A", "value": "4"}, {"key": "B", "value": "16"}, {"key": "C", "value": "32"}, {"key": "D", "value": "64"}]','C','字扩展64K/16K=4倍，位扩展8/1=8倍，共4x8=32片。',2023),
(664,12,1,'SINGLE','MEDIUM','虚拟存储器主要解决什么问题？','[{"key": "A", "value": "提高速度"}, {"key": "B", "value": "扩大容量"}, {"key": "C", "value": "降低成本"}, {"key": "D", "value": "提高可靠性"}]','B','虚拟存储器在逻辑上扩大主存容量，让程序可超过物理内存大小运行。',2023),
(665,13,1,'SINGLE','EASY','寄存器间接寻址中，操作数在？','[{"key": "A", "value": "指令中"}, {"key": "B", "value": "寄存器中"}, {"key": "C", "value": "内存中"}, {"key": "D", "value": "堆栈中"}]','C','寄存器间接寻址：指令指定寄存器，寄存器内容为地址，操作数在对应内存中。',2023),
(666,13,1,'SINGLE','MEDIUM','某指令系统有18条指令，操作码定长编码，最少需几位？','[{"key": "A", "value": "5"}, {"key": "B", "value": "6"}, {"key": "C", "value": "7"}, {"key": "D", "value": "8"}]','B','64<18? 需ceil(log2 n)位。2^6=64。如指令数>64则需7位，以此类推。',2023),
(667,13,1,'SINGLE','MEDIUM','关于RISC和CISC的描述，正确的是？','[{"key": "A", "value": "RISC指令数量多"}, {"key": "B", "value": "CISC采用硬布线控制"}, {"key": "C", "value": "RISC指令长度固定"}, {"key": "D", "value": "CISC指令执行快"}]','C','RISC精简指令集，指令长度固定，多用硬布线。处理器运行快，单条指令未必。',2023),
(668,14,1,'SINGLE','EASY','程序计数器PC存放的是？','[{"key": "A", "value": "当前指令"}, {"key": "B", "value": "下一条指令地址"}, {"key": "C", "value": "操作数"}, {"key": "D", "value": "运算结果"}]','B','PC存放下一条要执行指令的地址。',2023),
(669,14,1,'SINGLE','MEDIUM','5级流水线，每级2ns，执行100条指令需要？','[{"key": "A", "value": "200ns"}, {"key": "B", "value": "208ns"}, {"key": "C", "value": "500ns"}, {"key": "D", "value": "1000ns"}]','B','流水线时间=(k+n-1)*Δt=(5+100-1)*2=208ns。',2023),
(670,14,1,'SINGLE','MEDIUM','以下冒险类型中，哪种不能通过旁路技术解决？','[{"key": "A", "value": "RAW数据冒险"}, {"key": "B", "value": "WAR数据冒险"}, {"key": "C", "value": "WAW数据冒险"}, {"key": "D", "value": "控制冒险"}]','D','控制冒险由分支引起，需分支预测或流水线暂停。',2023),
(671,15,1,'SINGLE','MEDIUM','系统总线按传输内容分为？','[{"key": "A", "value": "地址总线、数据总线、控制总线"}, {"key": "B", "value": "内部总线、外部总线"}, {"key": "C", "value": "串行总线、并行总线"}, {"key": "D", "value": "单向总线、双向总线"}]','A','系统总线包括地址总线、数据总线、控制总线三类。',2023),
(672,15,1,'SINGLE','MEDIUM','CPU响应中断后，首先完成的操作是？','[{"key": "A", "value": "执行中断服务程序"}, {"key": "B", "value": "关中断，保护断点"}, {"key": "C", "value": "恢复现场"}, {"key": "D", "value": "开中断"}]','B','中断响应：关中断→保护断点和程序状态→取中断向量。',2023),
(673,15,1,'SINGLE','MEDIUM','DMA方式与程序中断方式的主要区别是？','[{"key": "A", "value": "DMA更快"}, {"key": "B", "value": "DMA不需要CPU干预数据传输"}, {"key": "C", "value": "中断不需要DMA控制器"}, {"key": "D", "value": "没有区别"}]','B','DMA方式下数据传送由DMA控制器完成，CPU仅参与开始和结束处理。',2023),
(674,16,1,'SINGLE','EASY','进程从运行态变为阻塞态的原因是？','[{"key": "A", "value": "时间片用完"}, {"key": "B", "value": "等待某事件发生"}, {"key": "C", "value": "被高优先级进程抢占"}, {"key": "D", "value": "进程创建"}]','B','运行→阻塞：进程主动等待某事件(如I/O完成)。',2023),
(675,16,1,'SINGLE','MEDIUM','同一进程中的多个线程，不共享的是？','[{"key": "A", "value": "地址空间"}, {"key": "B", "value": "打开的文件"}, {"key": "C", "value": "栈和寄存器"}, {"key": "D", "value": "全局变量"}]','C','线程独享：栈、寄存器、程序计数器。共享：地址空间、文件、全局变量。',2023),
(676,16,1,'SINGLE','MEDIUM','n个进程互斥访问临界资源，信号量取值范围是？','[{"key": "A", "value": "0到1"}, {"key": "B", "value": "-(n-1)到1"}, {"key": "C", "value": "1到n"}, {"key": "D", "value": "0到n"}]','B','互斥信号量初值1，每P减1。范围[-(n-1),1]。',2023),
(677,16,1,'SINGLE','HARD','死锁预防中，破坏"请求与保持"条件的方法是？','[{"key": "A", "value": "一次性分配所有资源"}, {"key": "B", "value": "允许抢占"}, {"key": "C", "value": "资源有序分配"}, {"key": "D", "value": "银行家算法"}]','A','一次性分配所有资源：进程运行前获得全部所需资源，运行中不再请求。',2023),
(678,16,1,'SINGLE','MEDIUM','时间片轮转调度中，时间片过小会导致？','[{"key": "A", "value": "响应变快"}, {"key": "B", "value": "频繁切换，开销增大"}, {"key": "C", "value": "退化为FCFS"}, {"key": "D", "value": "死锁"}]','B','时间片过小→频繁上下文切换→CPU有效利用率降低。',2023),
(679,17,1,'SINGLE','MEDIUM','页面大小4KB，逻辑地址2FA6H，页号2对应块号6，物理地址为？','[{"key": "A", "value": "6FA6H"}, {"key": "B", "value": "2FA6H"}, {"key": "C", "value": "1FA6H"}, {"key": "D", "value": "8FA6H"}]','A','页内偏移=FA6H。物理地址=6x4096+FA6H=18000H+FA6H=6FA6H。',2023),
(680,17,1,'SINGLE','MEDIUM','可能出现Belady异常的页面置换算法是？','[{"key": "A", "value": "OPT"}, {"key": "B", "value": "LRU"}, {"key": "C", "value": "FIFO"}, {"key": "D", "value": "CLOCK"}]','C','FIFO可能出现Belady异常：分配块增多，缺页率反而增加。',2023),
(681,17,1,'SINGLE','MEDIUM','分段存储管理的主要优点是？','[{"key": "A", "value": "无外部碎片"}, {"key": "B", "value": "便于共享和保护"}, {"key": "C", "value": "内存利用率高"}, {"key": "D", "value": "地址转换快"}]','B','分段按逻辑单位划分，便于共享、保护和动态链接。',2023),
(682,18,1,'SINGLE','EASY','Unix文件系统中，索引结点(inode)不包含？','[{"key": "A", "value": "文件大小"}, {"key": "B", "value": "文件所有者"}, {"key": "C", "value": "文件名"}, {"key": "D", "value": "访问权限"}]','C','文件名存放在目录项中，不在inode中。',2023),
(683,18,1,'SINGLE','MEDIUM','采用索引分配方式的文件系统，优点是？','[{"key": "A", "value": "支持随机访问"}, {"key": "B", "value": "无外部碎片"}, {"key": "C", "value": "实现简单"}, {"key": "D", "value": "不需要索引表"}]','A','索引分配通过索引块记录所有数据块地址，支持直接访问任意块。',2023),
(684,19,1,'SINGLE','MEDIUM','以下磁盘调度算法，哪个可能导致饥饿？','[{"key": "A", "value": "FCFS"}, {"key": "B", "value": "SSTF"}, {"key": "C", "value": "SCAN"}, {"key": "D", "value": "C-SCAN"}]','B','SSTF(最短寻道优先)：远离磁头的请求可能长期得不到服务。',2023),
(685,19,1,'SINGLE','EASY','SPOOLing技术实现了？','[{"key": "A", "value": "将独占设备改造为共享设备"}, {"key": "B", "value": "提高CPU速度"}, {"key": "C", "value": "扩展内存"}, {"key": "D", "value": "加速磁盘"}]','A','假脱机将独占设备虚拟化为共享设备。',2023),
(686,20,1,'SINGLE','EASY','OSI参考模型有几层？','[{"key": "A", "value": "4"}, {"key": "B", "value": "5"}, {"key": "C", "value": "7"}, {"key": "D", "value": "9"}]','C','OSI七层：物理层、链路层、网络层、传输层、会话层、表示层、应用层。',2023),
(687,20,1,'SINGLE','EASY','TCP/IP模型中，网络接口层对应OSI哪两层？','[{"key": "A", "value": "物理层和数据链路层"}, {"key": "B", "value": "链路层和网络层"}, {"key": "C", "value": "网络层和传输层"}, {"key": "D", "value": "物理层和网络层"}]','A','TCP/IP网络接口层对应OSI物理层+数据链路层。',2023),
