(692,23,1,'SINGLE','EASY','IP地址192.168.1.0/24的可用主机数是？','[{"key": "A", "value": "254"}, {"key": "B", "value": "255"}, {"key": "C", "value": "256"}, {"key": "D", "value": "253"}]','A','/24=主机号8位，可用=2^8-2=254。',2023),
