INSERT INTO question (id, chapter_id, subject_id, type, difficulty, content, options, answer, analysis, year) VALUES
(701,25,1,'SINGLE','EASY','HTTP状态码404表示？','[{"key": "A", "value": "请求成功"}, {"key": "B", "value": "资源未找到"}, {"key": "C", "value": "服务器错误"}, {"key": "D", "value": "重定向"}]','B','404 Not Found。200成功，500服务器错误，301/302重定向。',2023),
(702,25,1,'SINGLE','MEDIUM','SMTP使用的端口是？','[{"key": "A", "value": "21"}, {"key": "B", "value": "25"}, {"key": "C", "value": "80"}, {"key": "D", "value": "110"}]','B','SMTP:TCP 25发邮件。POP3:TCP 110收邮件。FTP:21。',2023),
(703,5,1,'SINGLE','EASY','在长度为18的顺序表中插入一个元素，平均需要移动的元素个数是？','[{"key": "A", "value": "n"}, {"key": "B", "value": "n/2"}, {"key": "C", "value": "(n-1)/2"}, {"key": "D", "value": "n-1"}]','B','共有n+1个插入位置，第i个位置需移动n-i+1个元素，平均移动n/2个。',2023),
(704,5,1,'SINGLE','EASY','在长度为18的顺序表中删除第8个元素，需要移动的元素个数是？','[{"key": "A", "value": "i"}, {"key": "B", "value": "n-i"}, {"key": "C", "value": "n-i+1"}, {"key": "D", "value": "n-i-1"}]','B','删除第i个元素后，后面的n-i个元素前移一位。',2023),
(705,5,1,'SINGLE','MEDIUM','在单链表中，在p所指结点之后插入s所指结点，正确的操作是？','[{"key": "A", "value": "p->next=s; s->next=p->next"}, {"key": "B", "value": "s->next=p->next; p->next=s"}, {"key": "C", "value": "p->next=s->next; s->next=p"}, {"key": "D", "value": "s->next=p; p->next=s"}]','B','先将s->next指向p的后继，再将p->next指向s。',2023),
(706,13,1,'SINGLE','MEDIUM','某指令系统有19条指令，操作码定长编码，最少需几位？','[{"key": "A", "value": "5"}, {"key": "B", "value": "6"}, {"key": "C", "value": "7"}, {"key": "D", "value": "8"}]','B','64<19? 需ceil(log2 n)位。2^6=64。如指令数>64则需7位，以此类推。',2024),
(707,13,1,'SINGLE','MEDIUM','关于RISC和CISC的描述，正确的是？','[{"key": "A", "value": "RISC指令数量多"}, {"key": "B", "value": "CISC采用硬布线控制"}, {"key": "C", "value": "RISC指令长度固定"}, {"key": "D", "value": "CISC指令执行快"}]','C','RISC精简指令集，指令长度固定，多用硬布线。处理器运行快，单条指令未必。',2024),
(708,14,1,'SINGLE','EASY','程序计数器PC存放的是？','[{"key": "A", "value": "当前指令"}, {"key": "B", "value": "下一条指令地址"}, {"key": "C", "value": "操作数"}, {"key": "D", "value": "运算结果"}]','B','PC存放下一条要执行指令的地址。',2024),
(709,14,1,'SINGLE','MEDIUM','5级流水线，每级2ns，执行100条指令需要？','[{"key": "A", "value": "200ns"}, {"key": "B", "value": "208ns"}, {"key": "C", "value": "500ns"}, {"key": "D", "value": "1000ns"}]','B','流水线时间=(k+n-1)*Δt=(5+100-1)*2=208ns。',2024),
(710,14,1,'SINGLE','MEDIUM','以下冒险类型中，哪种不能通过旁路技术解决？','[{"key": "A", "value": "RAW数据冒险"}, {"key": "B", "value": "WAR数据冒险"}, {"key": "C", "value": "WAW数据冒险"}, {"key": "D", "value": "控制冒险"}]','D','控制冒险由分支引起，需分支预测或流水线暂停。',2024),
(711,15,1,'SINGLE','MEDIUM','系统总线按传输内容分为？','[{"key": "A", "value": "地址总线、数据总线、控制总线"}, {"key": "B", "value": "内部总线、外部总线"}, {"key": "C", "value": "串行总线、并行总线"}, {"key": "D", "value": "单向总线、双向总线"}]','A','系统总线包括地址总线、数据总线、控制总线三类。',2024),
(712,15,1,'SINGLE','MEDIUM','CPU响应中断后，首先完成的操作是？','[{"key": "A", "value": "执行中断服务程序"}, {"key": "B", "value": "关中断，保护断点"}, {"key": "C", "value": "恢复现场"}, {"key": "D", "value": "开中断"}]','B','中断响应：关中断→保护断点和程序状态→取中断向量。',2024),
(713,15,1,'SINGLE','MEDIUM','DMA方式与程序中断方式的主要区别是？','[{"key": "A", "value": "DMA更快"}, {"key": "B", "value": "DMA不需要CPU干预数据传输"}, {"key": "C", "value": "中断不需要DMA控制器"}, {"key": "D", "value": "没有区别"}]','B','DMA方式下数据传送由DMA控制器完成，CPU仅参与开始和结束处理。',2024),
(714,16,1,'SINGLE','EASY','进程从运行态变为阻塞态的原因是？','[{"key": "A", "value": "时间片用完"}, {"key": "B", "value": "等待某事件发生"}, {"key": "C", "value": "被高优先级进程抢占"}, {"key": "D", "value": "进程创建"}]','B','运行→阻塞：进程主动等待某事件(如I/O完成)。',2024),
(715,16,1,'SINGLE','MEDIUM','同一进程中的多个线程，不共享的是？','[{"key": "A", "value": "地址空间"}, {"key": "B", "value": "打开的文件"}, {"key": "C", "value": "栈和寄存器"}, {"key": "D", "value": "全局变量"}]','C','线程独享：栈、寄存器、程序计数器。共享：地址空间、文件、全局变量。',2024),
(716,16,1,'SINGLE','MEDIUM','n个进程互斥访问临界资源，信号量取值范围是？','[{"key": "A", "value": "0到1"}, {"key": "B", "value": "-(n-1)到1"}, {"key": "C", "value": "1到n"}, {"key": "D", "value": "0到n"}]','B','互斥信号量初值1，每P减1。范围[-(n-1),1]。',2024),
(717,16,1,'SINGLE','HARD','死锁预防中，破坏"请求与保持"条件的方法是？','[{"key": "A", "value": "一次性分配所有资源"}, {"key": "B", "value": "允许抢占"}, {"key": "C", "value": "资源有序分配"}, {"key": "D", "value": "银行家算法"}]','A','一次性分配所有资源：进程运行前获得全部所需资源，运行中不再请求。',2024),
(718,16,1,'SINGLE','MEDIUM','时间片轮转调度中，时间片过小会导致？','[{"key": "A", "value": "响应变快"}, {"key": "B", "value": "频繁切换，开销增大"}, {"key": "C", "value": "退化为FCFS"}, {"key": "D", "value": "死锁"}]','B','时间片过小→频繁上下文切换→CPU有效利用率降低。',2024),
(719,17,1,'SINGLE','MEDIUM','页面大小4KB，逻辑地址2FA6H，页号2对应块号6，物理地址为？','[{"key": "A", "value": "6FA6H"}, {"key": "B", "value": "2FA6H"}, {"key": "C", "value": "1FA6H"}, {"key": "D", "value": "8FA6H"}]','A','页内偏移=FA6H。物理地址=6x4096+FA6H=18000H+FA6H=6FA6H。',2024),
(720,17,1,'SINGLE','MEDIUM','可能出现Belady异常的页面置换算法是？','[{"key": "A", "value": "OPT"}, {"key": "B", "value": "LRU"}, {"key": "C", "value": "FIFO"}, {"key": "D", "value": "CLOCK"}]','C','FIFO可能出现Belady异常：分配块增多，缺页率反而增加。',2024),
(721,17,1,'SINGLE','MEDIUM','分段存储管理的主要优点是？','[{"key": "A", "value": "无外部碎片"}, {"key": "B", "value": "便于共享和保护"}, {"key": "C", "value": "内存利用率高"}, {"key": "D", "value": "地址转换快"}]','B','分段按逻辑单位划分，便于共享、保护和动态链接。',2024),
(722,18,1,'SINGLE','EASY','Unix文件系统中，索引结点(inode)不包含？','[{"key": "A", "value": "文件大小"}, {"key": "B", "value": "文件所有者"}, {"key": "C", "value": "文件名"}, {"key": "D", "value": "访问权限"}]','C','文件名存放在目录项中，不在inode中。',2024),
(723,18,1,'SINGLE','MEDIUM','采用索引分配方式的文件系统，优点是？','[{"key": "A", "value": "支持随机访问"}, {"key": "B", "value": "无外部碎片"}, {"key": "C", "value": "实现简单"}, {"key": "D", "value": "不需要索引表"}]','A','索引分配通过索引块记录所有数据块地址，支持直接访问任意块。',2024),
(724,19,1,'SINGLE','MEDIUM','以下磁盘调度算法，哪个可能导致饥饿？','[{"key": "A", "value": "FCFS"}, {"key": "B", "value": "SSTF"}, {"key": "C", "value": "SCAN"}, {"key": "D", "value": "C-SCAN"}]','B','SSTF(最短寻道优先)：远离磁头的请求可能长期得不到服务。',2024),
(725,19,1,'SINGLE','EASY','SPOOLing技术实现了？','[{"key": "A", "value": "将独占设备改造为共享设备"}, {"key": "B", "value": "提高CPU速度"}, {"key": "C", "value": "扩展内存"}, {"key": "D", "value": "加速磁盘"}]','A','假脱机将独占设备虚拟化为共享设备。',2024),
(726,20,1,'SINGLE','EASY','OSI参考模型有几层？','[{"key": "A", "value": "4"}, {"key": "B", "value": "5"}, {"key": "C", "value": "7"}, {"key": "D", "value": "9"}]','C','OSI七层：物理层、链路层、网络层、传输层、会话层、表示层、应用层。',2024),
(727,20,1,'SINGLE','EASY','TCP/IP模型中，网络接口层对应OSI哪两层？','[{"key": "A", "value": "物理层和数据链路层"}, {"key": "B", "value": "链路层和网络层"}, {"key": "C", "value": "网络层和传输层"}, {"key": "D", "value": "物理层和网络层"}]','A','TCP/IP网络接口层对应OSI物理层+数据链路层。',2024),
(728,21,1,'SINGLE','MEDIUM','曼彻斯特编码的编码效率为？','[{"key": "A", "value": "25%"}, {"key": "B", "value": "50%"}, {"key": "C", "value": "75%"}, {"key": "D", "value": "100%"}]','B','曼彻斯特编码每位有两个码元，效率50%。',2024),
(729,22,1,'SINGLE','MEDIUM','CSMA/CD协议中争用期长度为？','[{"key": "A", "value": "端到端传播时延"}, {"key": "B", "value": "两倍端到端传播时延"}, {"key": "C", "value": "数据帧发送时延"}, {"key": "D", "value": "随机时间"}]','B','争用期=2tau(两倍单程传播时延，即往返时延RTT)。',2024),
(730,22,1,'SINGLE','MEDIUM','以太网最小帧长64字节，目的是？','[{"key": "A", "value": "提高效率"}, {"key": "B", "value": "确保冲突检测"}, {"key": "C", "value": "对齐数据"}, {"key": "D", "value": "减少开销"}]','B','最小帧长确保发送完之前能检测到冲突。',2024),
(731,22,1,'SINGLE','MEDIUM','生成多项式G(x)=x^3+x+1，CRC校验码长度为？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','C','CRC校验码位数=生成多项式最高次幂=3。',2024),
(732,23,1,'SINGLE','EASY','IP地址192.168.1.0/24的可用主机数是？','[{"key": "A", "value": "254"}, {"key": "B", "value": "255"}, {"key": "C", "value": "256"}, {"key": "D", "value": "253"}]','A','/24=主机号8位，可用=2^8-2=254。',2024),
(733,23,1,'SINGLE','MEDIUM','192.168.1.0/26划分后，每个子网可用地址数？','[{"key": "A", "value": "62"}, {"key": "B", "value": "64"}, {"key": "C", "value": "30"}, {"key": "D", "value": "32"}]','A','/26=主机号6位，可用=2^6-2=62。',2024),
(734,23,1,'SINGLE','MEDIUM','以下使用链路状态算法的路由协议是？','[{"key": "A", "value": "RIP"}, {"key": "B", "value": "OSPF"}, {"key": "C", "value": "BGP"}, {"key": "D", "value": "IGRP"}]','B','OSPF基于Dijkstra算法，使用链路状态数据库。',2024),
(735,23,1,'SINGLE','MEDIUM','NAT的主要作用是？','[{"key": "A", "value": "加密"}, {"key": "B", "value": "地址转换"}, {"key": "C", "value": "过滤"}, {"key": "D", "value": "加速"}]','B','NAT实现私有IP与公网IP转换，缓解IPv4枯竭。',2024),
(736,24,1,'SINGLE','EASY','TCP建立连接需要几次握手？','[{"key": "A", "value": "1"}, {"key": "B", "value": "2"}, {"key": "C", "value": "3"}, {"key": "D", "value": "4"}]','C','TCP三次握手：SYN->SYN+ACK->ACK。',2024),
(737,24,1,'SINGLE','MEDIUM','收到3个重复ACK触发什么？','[{"key": "A", "value": "慢开始"}, {"key": "B", "value": "快重传"}, {"key": "C", "value": "拥塞避免"}, {"key": "D", "value": "连接重置"}]','B','3个重复ACK触发快重传，不等超时就重传。',2024),
(738,24,1,'SINGLE','MEDIUM','以下适合用UDP的应用是？','[{"key": "A", "value": "文件传输"}, {"key": "B", "value": "邮件"}, {"key": "C", "value": "视频直播"}, {"key": "D", "value": "网页"}]','C','视频直播实时性要求高，可容忍少量丢包，适合UDP。',2024),
(739,24,1,'SINGLE','MEDIUM','TCP实现流量控制靠什么？','[{"key": "A", "value": "拥塞窗口"}, {"key": "B", "value": "滑动窗口(rwnd)"}, {"key": "C", "value": "慢开始"}, {"key": "D", "value": "快重传"}]','B','TCP通过接收方通告窗口(rwnd)实现端到端流量控制。',2024),
(740,25,1,'SINGLE','EASY','DNS使用的传输层协议和端口是？','[{"key": "A", "value": "TCP 53"}, {"key": "B", "value": "UDP 53"}, {"key": "C", "value": "TCP+UDP 53"}, {"key": "D", "value": "HTTP 80"}]','C','DNS查询用UDP 53，区域传送用TCP 53。',2024),
(741,25,1,'SINGLE','EASY','HTTP状态码404表示？','[{"key": "A", "value": "请求成功"}, {"key": "B", "value": "资源未找到"}, {"key": "C", "value": "服务器错误"}, {"key": "D", "value": "重定向"}]','B','404 Not Found。200成功，500服务器错误，301/302重定向。',2024),
(742,25,1,'SINGLE','MEDIUM','SMTP使用的端口是？','[{"key": "A", "value": "21"}, {"key": "B", "value": "25"}, {"key": "C", "value": "80"}, {"key": "D", "value": "110"}]','B','SMTP:TCP 25发邮件。POP3:TCP 110收邮件。FTP:21。',2024),
